     ///
     /// Return any comment included in the registration for this language.
     ///
     #[cfg(feature = "comment")]
     pub fn comment(&self) -> Option<&'static str> {
         match self {
             Self::Hbs => Some("Code element for 639-1 has been deprecated"),
             _ => None
         }
     }

